#include <stdio.h>
#include <stdlib.h>
#include <assert.h>

#define MAX_SIZE 100

// since we don't have inbuilt queue structure in C, we've created our own
typedef struct {
    int x;
    int y;
} Pair;

typedef struct {
    Pair queue[MAX_SIZE * MAX_SIZE];
    int front;
    int rear;
} Queue;

void enqueue(Queue *q, Pair p) {
    q->queue[q->rear++] = p;
}

Pair dequeue(Queue *q) {
    return q->queue[q->front++];
}

int isEmpty(Queue *q) {
    return q->front == q->rear;
}

int minTimeToRot(int grid[][MAX_SIZE], int n, int m) {
    int rows = n;
    int cols = m;
    int visited[MAX_SIZE][MAX_SIZE];

    for (int i = 0; i < rows; i++) {
        for (int j = 0; j < cols; j++) {
            visited[i][j] = grid[i][j];
        }
    }

    Queue rottenQueue;
    rottenQueue.front = 0;
    rottenQueue.rear = 0;
    int freshOrangeCount = 0;

    for (int i = 0; i < rows; i++) {
        for (int j = 0; j < cols; j++) {
            if (visited[i][j] == 2) {
                enqueue(&rottenQueue, (Pair){i, j});
            }
            if (visited[i][j] == 1) {
                freshOrangeCount++;
            }
        }
    }

    if (freshOrangeCount == 0)
        return 0;
    if (isEmpty(&rottenQueue))
        return -1;

    int minutes = -1;
    Pair directions[] = {{1, 0},{-1, 0},{0, -1},{0, 1}};

    while (!isEmpty(&rottenQueue)) {
        int size = rottenQueue.rear - rottenQueue.front;
        while (size--) {
            Pair it = dequeue(&rottenQueue);
            int x = it.x;
            int y = it.y;
            for (int k = 0; k < 4; k++) {
                int i = x + directions[k].x;
                int j = y + directions[k].y;
                if (i >= 0 && i < rows && j >= 0 && j < cols && visited[i][j] == 1) {
                    visited[i][j] = 2;
                    freshOrangeCount--;
                    enqueue(&rottenQueue, (Pair){i, j});
                }
            }
        }
        minutes++;
    }

    if (freshOrangeCount == 0)
        return minutes;
    return -1;
}

int main() {
    int n, m;
    scanf("%d %d", &n, &m);

    assert(1 <= n && n <= 100);
    assert(1 <= m && m <= 100);

    int mat[MAX_SIZE][MAX_SIZE];

    for (int i = 0; i < n; i++) {
